return ['domain'=>'capability-manager-enhanced>= 2 && n % 10 <= 4 && (n % 100 < 10 || n % 100 >= 20) ? 1 : 2);n%10<=4 && (n%100<10 || n%100>=20) ? 1: 2);','plural-forms'=>'nplurals=3; plural=(n % 10 == 1 && n % 100 != 11 ? 0 : n % 10 >= 2 && n % 10 <= 4 && (n % 100 < 10 || n % 100 >= 20) ? 1 : 2);','language'=>'ru_RU','project-id-version'=>'PublishPress Capabilities 2.40.0','pot-creation-date'=>'2026-03-23T21:48:55+00:00','po-revision-date'=>'2026-03-24 15:04+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['PublishPress Capabilities'=>'Возможности PublishPress','https://publishpress.com/capability-manager/'=>'https://publishpress.com/capability-manager/','PublishPress Capabilities is the access control plugin for WordPress. You can manage all your WordPress user roles, from Administrators to Subscribers.'=>'PublishPress Capabilities — это плагин контроля доступа для WordPress. Вы можете управлять всеми ролями пользователей WordPress, от администраторов до подписчиков.','PublishPress'=>'PublishPress','https://publishpress.com/'=>'https://publishpress.com/','%1s Error: %2s  PublishPress Capabilities cannot function because another copy of the plugin is active.'=>'%1s Ошибка: %2s Функции PublishPress не могут работать, потому что другая копия плагина активна.','This plugin can be deleted.'=>'Этот плагин можно удалить.','You can block pages by URL or hide Admin elements by entering a CSS class or ID. This feature is available in PublishPress Capabilities Pro.'=>'Вы можете блокировать страницы по URL или скрывать элементы администратора, введя CSS класс или ID. Эта функция доступна в PublishPress Capabilities Pro.','Upgrade to Pro'=>'Обновить до Pro','Admin Menu Restrictions'=>'Ограничения меню администратора','You can restrict access to admin menu screens. You can also edit, change, add, or remove links from the WordPress admin menu. This feature is available in PublishPress Capabilities Pro.'=>'Вы можете ограничить доступ к экранам меню администратора. Вы также можете редактировать, изменять, добавлять или удалять ссылки из меню администратора WordPress. Эта функция доступна в PublishPress Capabilities Pro.','You\'re using PublishPress Capabilities Free. The Pro version has more features and support. %sUpgrade to Pro%s'=>'Вы используете PublishPress Capabilities Free. Профессиональная версия имеет больше функций и поддержку. %sПерейти на Pro%s','Admin Menus'=>'Меню администратора','Hide CSS Elements'=>'Скрыть элементы CSS','Block by URL'=>'Блокировать по URL','Admin Menus allows you to edit the admin menu links and control who has access.'=>'Админские меню позволяют редактировать ссылки на меню администратора и контролировать, кто имеет доступ.','Select pages...'=>'Выберите страницы...','You can select page types where this element will be added.'=>'Вы можете выбрать типы страниц, на которые будет добавлен этот элемент.','Metaboxes'=>'Метабоксы','Checklist'=>'Контрольный список','Editorial Comments'=>'Редакционные комментарии','Notifications'=>'Уведомления','TaxoPress - Settings'=>'TaxoPress - Настройки','You can hide plugin metaboxes. You can also hide specific items by entering their CSS class or ID. This feature is available in PublishPress Capabilities Pro.'=>'Вы можете скрыть метабоксы плагина. Вы также можете скрыть конкретные элементы, введя их CSS-класс или ID. Эта функция доступна в PublishPress Capabilities Pro.','Custom Items'=>'Пользовательские элементы','Custom item one'=>'Пользовательский элемент один','Permalink: Descriptive Caption'=>'Постоянная ссылка: Описательная подпись','Page Attributes: Order'=>'Атрибуты страницы: Порядок','You can use Frontend Features to target specific posts and pages. This feature is available in PublishPress Capabilities Pro.'=>'Вы можете использовать функции на фронтенде, чтобы нацелиться на конкретные записи и страницы. Эта функция доступна в PublishPress Capabilities Pro.','Select post types...'=>'Выберите типы постов...','This will add a metabox on the post editing screen. You can use this feature to add body classes only for that post.'=>'Это добавит метабокс на экран редактирования поста. Вы можете использовать эту функцию, чтобы добавить классы тела только для этого поста.','Drag multiple roles selection to change roles order.'=>'Перетащите выбор нескольких ролей, чтобы изменить порядок ролей.','Page title'=>'Название страницы','Rank Math SEO'=>'Rank Math SEO','Capabilities'=>'Возможности','No permission!'=>'Нет разрешения!','Invalid nonce token!'=>'Недействительный токен nonce!','Error: wrong data'=>'Ошибка: неверные данные','An error occured!'=>'Произошла ошибка!','Security check failed'=>'Проверка безопасности не удалась','Permission denied'=>'Доступ запрещен','Settings updated successfully.'=>'Настройки успешно обновлены.','Logged In Users'=>'Вошедшие пользователи','Logged Out Users'=>'Вышедшие пользователи','PublishPress Capabilities Menu Restriction'=>'Ограничение меню PublishPress Capabilities','This menu is restricted for the following roles'=>'Это меню ограничено для следующих ролей','Dashboard'=>'Панель управления','Roles'=>'Роли','Settings'=>'Настройки','Display this notice'=>'Показать это уведомление','Silence this notice'=>'Скрыть это уведомление','Hide this notice'=>'Скрыть это уведомление','Move to Hidden Notices'=>'Переместить в скрытые уведомления','Displayed notices will no longer be removed from admin pages.'=>'Показанные уведомления больше не будут удаляться со страниц администратора.','This notice will be moved to the "Silenced Notices" tab and you will not receive a notification if it appears again.'=>'Это уведомление будет перемещено на вкладку "Приглушенные уведомления" и вы не получите уведомление, если оно появится снова.','Admin Notices'=>'Уведомления администратора','Hidden Notices'=>'Скрытые уведомления','Silenced Notices'=>'Скрытые уведомления','There are currently no admin notices.'=>'В данный момент нет уведомлений администратора.','Edit the settings.'=>'Изменить настройки.','You do not have permission to manage admin notices.'=>'У вас нет разрешения для управления уведомлениями админа.','Invalid action. Reload this page and try again.'=>'Недействительное действие. Перезагрузите эту страницу и попробуйте снова.','Invalid form.'=>'Недействительная форма.','Admin notice status updated successfully.'=>'Статус уведомления администратора успешно обновлён.','Warning: This role cannot access the dashboard without the read capability. %1$sClick here to fix this now%2$s.'=>'Предупреждение: Эта роль не может получить доступ к панели управления без возможности чтения. %1$sНажмите здесь, чтобы исправить это сейчас%2$s.','Negate All'=>'Отменить все','Negate None'=>'Не отменять ничего','Role Capabilities'=>'Возможности Роли','Search capabilities...'=>'Поиск возможностей...','Nav Menus (Block)'=>'Навигационные меню (блок)','Block'=>'Блокировать','Nav Menus (Legacy)'=>'Навигационные меню (наследие)','Legacy'=>'Устаревший','&nbsp;'=>'&nbsp;','Visibility'=>'Видимость','Editing'=>'Редактирование','Deletion'=>'Удаление','Taxonomies'=>'Таксономии','Listing'=>'Список','Create Revision'=>'Создать ревизию','Submit Revision'=>'Отправить правку','Approve Revision'=>'Одобрить ревизию','Can read posts which are currently published with private visibility.'=>'Может читать записи, которые в настоящее время опубликованы с приватной видимостью.','Has basic editing capability (but may need other capabilities based on post status and ownership).'=>'Имеет базовую возможность редактирования (но может потребоваться другие возможности в зависимости от статуса поста и владения).','Can edit posts which were created by other users.'=>'Может редактировать записи, которые были созданы другими пользователями.','Can edit posts which are currently published.'=>'Может редактировать записи, которые в настоящее время опубликованы.','Can edit posts which are currently published with private visibility.'=>'Может редактировать записи, которые в настоящее время опубликованы с приватной видимостью.','Can make a post publicly visible.'=>'Может сделать запись публично видимой.','Has basic deletion capability (but may need other capabilities based on post status and ownership).'=>'Имеет базовую возможность удаления (но может потребоваться другие возможности в зависимости от статуса поста и владения).','Can delete posts which were created by other users.'=>'Может удалять записи, которые были созданы другими пользователями.','Can delete posts which are currently published.'=>'Может удалять записи, которые в настоящее время опубликованы.','Can delete posts which are currently published with private visibility.'=>'Может удалять записи, которые в настоящее время опубликованы с приватной видимостью.','Multisite'=>'Мультисайт','Admin'=>'Администратор','Invalid Capabilities'=>'Недействительные возможности','Additional'=>'Дополнительно','Term %s Capabilities'=>'Возможности термина %s','%s Capabilities'=>'%s Возможности','Post %s Capabilities'=>'Возможности поста %s','Taxonomy'=>'Таксономия','Filter by taxonomy'=>'Фильтр по таксономии','Filter by post type'=>'Фильтровать по типу записи','The slug for this taxonomy is %s'=>'Slug для этой таксономии - %s','The slug for this post type is %s'=>'Slug для этого типа поста - %s','%s: assigned by Permission Group'=>'%s: назначено группой разрешений','This capability is %s'=>'Эта возможность - %s','This capability is controlled by %s'=>'Эта возможность контролируется %s','This capability is controlled by %s Use the sidebar settings to allow this to be controlled independently.'=>'Эта возможность контролируется %s Используйте настройки боковой панели, чтобы разрешить это контролировать независимо.','Use the sidebar settings to allow this to be controlled independently.'=>'Используйте настройки боковой панели, чтобы это можно было контролировать независимо.','This capability is not available for this post type.'=>'Эта возможность недоступна для данного типа записи.','Admin listing access is normally provided by the "Edit" capabilities. These "List" capabilities only apply if the corresponding "Edit" capability is missing. Also, these "List" capabilities can grant access, but not deny access.'=>'Доступ к списку администратора обычно предоставляется функциями "Редактировать". Эти функции "Список" применяются только в том случае, если соответствующая функция "Редактировать" отсутствует. Также эти функции "Список" могут предоставлять доступ, но не могут его отменить.','Filter by capability'=>'Фильтровать по возможности','No results found. Please try again with a different word.'=>'Результатов не найдено. Пожалуйста, попробуйте снова с другим словом.','check / uncheck all'=>'выбрать / снять выбор со всех','Capability Name'=>'Название возможности','WordPress Core Capabilities'=>'Возможности ядра WordPress','Plugin Capabilities &ndash; %s'=>'Возможности плагина &ndash; %s','The User Testing feature also requires the %1$s edit_users %2$s capability.'=>'Функция пользовательского тестирования также требует возможности %1$s edit_users %2$s.','The following entries have no effect. Please assign desired capabilities on the Editing / Deletion / Private tabs.'=>'Следующие записи не имеют эффекта. Пожалуйста, назначьте желаемые возможности на вкладках Редактирование / Удаление / Приватные.','Additional Capabilities'=>'Дополнительные возможности','You have no additional capabilities.'=>'У вас нет дополнительных возможностей.','Capabilities allows you change the permissions for any user role.'=>'Возможности позволяют вам изменять права для любой пользовательской роли.','%1$s = Capability granted %2$s'=>'%1$s = Возможность предоставлена %2$s','usage key'=>'ключ использования','%1$s = Capability not granted %2$s'=>'%1$s = Возможность не предоставлена %2$s','%1$s = Capability denied, even if granted by another role %2$s'=>'%1$s = Возможность отклонена, даже если предоставлена другой ролью %2$s','You can also configure this role as a %sPermission Group%s.'=>'Вы также можете настроить эту роль как группу %sРазрешений%s.','How to use Capabilities'=>'Как использовать возможности','View Documentation'=>'Просмотреть документацию','Capabilities is Safe to Use'=>'Возможности безопасны для использования','WordPress stores role capabilities in your database, where they remain even if the plugin is deactivated.'=>'WordPress хранит возможности ролей в вашей базе данных, где они остаются, даже если плагин деактивирован.','Whenever you use PublishPress Capabilities to save changes, it also creates a backup which you can use to restore a previous configuration.'=>'Каждый раз, когда вы используете возможности PublishPress для сохранения изменений, создается резервная копия, которую вы можете использовать для восстановления предыдущей конфигурации.','Go to the Backup feature'=>'Перейти к функции резервного копирования','Add a New Capability'=>'Добавить новую возможность','Add to role'=>'Добавить в роль','New capabilities are controlled on the Additonal tab.'=>'Новые возможности контролируются на вкладке Дополнительно.','PublishPress Permissions'=>'Разрешения PublishPress','Automatically define type-specific capabilities for your custom post types and taxonomies'=>'Автоматически определяйте функции, специфичные для типов, для ваших пользовательских типов постов и таксономий','Assign standard WP roles supplementally for a specific post type'=>'Дополнительно назначьте стандартные роли WP для конкретного типа поста','Assign custom WP roles supplementally for a specific post type <em>(Pro)</em>'=>'Дополнительно назначьте пользовательские WP роли для конкретного типа поста <em>(Pro)</em>','Customize reading permissions per-category or per-post'=>'Настроить разрешения на чтение по категориям или по постам','Customize editing permissions per-category or per-post <em>(Pro)</em>'=>'Настроить разрешения на редактирование по категориям или по постам <em>(Pro)</em>','Custom Post Visibility statuses, fully implemented throughout wp-admin <em>(Pro)</em>'=>'Пользовательские статусы видимости постов, полностью реализованные на всех страницах wp-admin <em>(Pro)</em>','Custom Moderation statuses for access-controlled, multi-step publishing workflow <em>(Pro)</em>'=>'Пользовательские статусы модерации для контроля доступа, многошагового рабочего процесса публикации <em>(Pro)</em>','Regulate permissions for Edit Flow post statuses <em>(Pro)</em>'=>'Регулировать разрешения для статусов публикаций Edit Flow <em>(Pro)</em>','Customize the moderated editing of published content with Revisionary or Post Forking <em>(Pro)</em>'=>'Настройте модерацию редактирования опубликованного контента с помощью Revisionary или Post Forking <em>(Pro)</em>','Grant Spectator, Participant or Moderator access to specific bbPress forums <em>(Pro)</em>'=>'Предоставьте доступ Зрителю, Участнику или Модератору к конкретным форумам bbPress <em>(Pro)</em>','Grant supplemental content permissions to a BuddyPress group <em>(Pro)</em>'=>'Предоставить разрешения на дополнительный контент группе BuddyPress <em>(Pro)</em>','WPML integration to mirror permissions to translations <em>(Pro)</em>'=>'Интеграция WPML для зеркалирования разрешений к переводам <em>(Pro)</em>','Member support forum'=>'Форум поддержки участников','%1$sgrab%2$s %3$s'=>'%1$sgrab%2$s %3$s','%s (free install)'=>'%s (бесплатная установка)','%1$sbuy%2$s %3$s'=>'%1$sbuy%2$s %3$s','%s info/purchase'=>'%s информация/покупка','Role level is mostly deprecated. However, it still determines eligibility for Post Author assignment and limits the application of user editing capabilities.'=>'Уровень роли в основном устарел. Тем не менее, он все еще определяет право на назначение автора поста и ограничивает применение возможностей редактирования пользователя.','Level:'=>'Уровень:','Create this role definition in new (future) sites'=>'Создать это определение роли на новых (будущих) сайтах','Include in new sites.'=>'Включить в новые сайты.','Copy / update this role definition to all sites now'=>'Скопировать / обновить это определение роли на всех сайтах сейчас','Sync role to all sites.'=>'Синхронизировать роль на всех сайтах.','Copy option settings to all sites now'=>'Скопировать настройки опции на все сайты сейчас','Sync options to all sites.'=>'Синхронизировать параметры на всех сайтах.','You do not have permission to restore backup.'=>'У вас нет разрешения восстанавливать резервную копию.','New backup saved.'=>'Новая резервная копия сохранена.','Roles and Capabilities restored from initial backup.'=>'Роли и Возможности восстановлены из начальной резервной копии.','Restore failed. No backup found.'=>'Восстановление не удалось. Резервная копия не найдена.','%s restored from last backup.'=>'%s восстановлено из последней резервной копии.','Roles and Capabilities restored from selected auto-backup.'=>'Роли и Возможности восстановлены из выбранной автоматической резервной копии.','Please upload a file to import'=>'Пожалуйста, загрузите файл для импорта','Please upload a valid .json file'=>'Пожалуйста, загрузите действительный файл .json','Error importing settings! Please try again.'=>'Ошибка импорта настроек! Пожалуйста, попробуйте снова.','Error importing settings! Please check that you uploaded a valid json file.'=>'Ошибка импорта настроек! Пожалуйста, убедитесь, что вы загрузили действительный файл json.','%s successfully imported from uploaded data.'=>'%s успешно импортировано из загруженных данных.','Needed function to create default roles not found!'=>'Необходимая функция для создания стандартных ролей не найдена!','Roles and Capabilities reset to WordPress defaults'=>'Роли и Возможности сброшены до значений по умолчанию WordPress','Backup Tool for PublishPress Capabilities'=>'Инструмент резервного копирования для возможностей PublishPress','Restore'=>'Восстановить','Backup'=>'Резервное копирование','Reset Roles'=>'Сбросить роли','Export / Import'=>'Экспорт / Импорт','Backup Roles and Capabilities'=>'Резервное копирование ролей и возможностей','PublishPress Capabilities automatically creates a backup on installation and whenever you save changes. The initial backup and last %d auto-backups are kept.'=>'PublishPress Capabilities автоматически создает резервную копию при установке и каждый раз, когда вы сохраняете изменения. Начальная резервная копия и последние %d автоматические резервные копии сохраняются.','A backup created on this screen replaces any previous manual backups, but is never automatically replaced.'=>'Резервная копия, созданная на этом экране, заменяет любые предыдущие ручные резервные копии, но никогда не заменяется автоматически.','Manual Backup'=>'Ручное резервное копирование','Last Manual Backup - %s'=>'Последнее ручное резервное копирование - %s','Last Backup'=>'Последняя резервная копия','Restore Previous Roles and Capabilities'=>'Восстановить предыдущие роли и возможности','PublishPress Capabilities automatically creates a backup on installation and whenever you save changes.'=>'PublishPress Capabilities автоматически создает резервную копию при установке и каждый раз, когда вы сохраняете изменения.','On this screen, you can restore an earlier version of your roles and capabilities.'=>'На этом экране вы можете восстановить более раннюю версию своих ролей и возможностей.','Available Backups:'=>'Доступные резервные копии:','all roles'=>'все роли','Manual backup of %s (%s)'=>'Ручное резервное копирование %s (%s)','Auto-backup of all roles (%s)'=>'Авто-резервное копирование всех ролей (%s)','Initial backup of all roles'=>'Первичный резервный копия всех ролей','Restore Selected Roles'=>'Восстановить выбранные роли','Show changes from current roles only'=>'Показать изменения только для текущих ролей','Initial Backup - %s'=>'Первичный резервный копия - %s','Initial Backup'=>'Первичный резервный копия','%s (%s roles)'=>'%s (%s роли)','(this role will be removed if you restore backup)'=>'(эта роль будет удалена, если вы восстановите резервную копию)','%s (level %s)'=>'%s (уровень %s)','No changes'=>'Нет изменений','Reset WordPress Defaults'=>'Сбросить стандартные настройки WordPress','Warning:'=>'Предупреждение:','Reseting default Roles and Capabilities will set them to the WordPress install defaults.'=>'Сброс значений по умолчанию для ролей и возможностей приведет их к значениям по умолчанию установки WordPress.','If you have installed any plugin that adds new roles or capabilities, these will be lost.'=>'Если вы установили какой-либо плагин, который добавляет новые роли или возможности, они будут потеряны.','It is recommended to use this only as a last resource!'=>'Рекомендуется использовать это только в качестве последнего средства!','Reset Roles and Capabilities to WordPress defaults'=>'Сбросить роли и возможности к стандартным настройкам WordPress','You are about to reset Roles and Capabilities to WordPress defaults.
 \'Cancel\' to stop, \'OK\' to reset.'=>'Вы собираетесь сбросить роли и возможности до значений по умолчанию WordPress. \'Отмена\' для остановки, \'ОК\' для сброса.','Reset to WordPress defaults'=>'Сбросить к стандартным настройкам WordPress','Export Settings'=>'Экспорт настроек','Export the plugin settings for this site as a .json file. This allows you to easily import the configuration into another site.'=>'Экспортируйте настройки плагина для этого сайта в файл .json. Это позволит вам легко импортировать конфигурацию на другой сайт.','Roles and Capabilities'=>'Роли и Возможности','Export'=>'Экспорт','Import Settings'=>'Импорт настроек','Please make a \'Manual Backup\' in the backup tab to enable backup restore in case anything goes wrong.'=>'Пожалуйста, сделайте \'Ручное резервное копирование\' на вкладке резервного копирования, чтобы включить восстановление резервной копии в случае, если что-то пойдет не так.','Import the plugin settings from a .json file. This file can be obtained by exporting the settings on another site using the form above.'=>'Импортируйте настройки плагина из файла .json. Этот файл можно получить, экспортировав настройки на другом сайте, используя форму выше.','Before importing, we recommend using the "Backup" tab to create a backup of your current settings.'=>'Перед импортом мы рекомендуем использовать вкладку "Резервная копия", чтобы создать резервную копию ваших текущих настроек.','Admin Feature Restrictions'=>'Ограничения функций администратора','Toggle all'=>'Переключить все','Wildcard enabled'=>'Используются подстановочные знаки','URL targeted'=>'Целевой URL','URL wildcard'=>'Шаблон URL','Edit'=>'Редактировать','Admin Features allows you to remove elements from the admin area and toolbar.'=>'Функции администратора позволяют удалять элементы из области администратора и панели инструментов.','No change'=>'Нет изменений','This feature is denied'=>'Эта функция запрещена','How to use Admin Features'=>'Как использовать функции администратора','Admin Features Settings'=>'Настройки функций администратора','Hide Submenus'=>'Скрыть подменю','Custom style "%s" saved successfully.'=>'Пользовательский стиль "%s" успешно сохранён.','Custom style "%s" deleted successfully.'=>'Пользовательский стиль "%s" успешно удалён.','Custom style name cannot be empty.'=>'Имя пользовательского стиля не может быть пустым.','Admin styles saved successfully.'=>'Стили администратора успешно сохранены.','Admin Styles'=>'Стили администратора','Save for all Roles'=>'Сохранить для всех Ролей','Save for %s'=>'Сохранить для %s','Setting'=>'Настройка','Value'=>'Значение','Admin Color Scheme'=>'Цветовая схема администратора','Sets the admin color scheme for all users. Click a scheme to preview it instantly.'=>'Устанавливает цветовую схему администратора для всех пользователей. Щелкните на схему, чтобы мгновенно просмотреть её.','Start from template'=>'Начать с шаблона','Blank Template'=>'Пустой шаблон','Add Custom Style'=>'Добавить пользовательский стиль','Edit custom style'=>'Редактировать пользовательский стиль','Edit Color Style'=>'Редактировать цветовой стиль','Customize colors for different admin elements. Changes are previewed instantly.'=>'Настройте цвета для различных элементов администратора. Изменения отображаются мгновенно.','Add more than one custom admin styles. This feature is available in PublishPress Capabilities Pro.'=>'Добавьте более одного пользовательского стиля администратора. Эта функция доступна в PublishPress Capabilities Pro.','Add CSS selectors (class or ID), choose a style variation, and set a brand color.'=>'Добавьте CSS-селекторы (класс или ID), выберите вариант стиля и установите цвет бренда.','Add New Element'=>'Добавить новый элемент','Selector'=>'Селектор','e.g. .publishpress-wrap h1, #my-plugin-header'=>'например, .publishpress-wrap h1, #my-plugin-header','Variation'=>'Вариант','Background'=>'Фон','Text'=>'Текст','Border'=>'Граница','Brand Color'=>'Цвет бренда','Remove'=>'Удалить','Custom Style Name'=>'Название пользовательского стиля','e.g., Company Branding, Dark Mode'=>'напр., Брендинг компании, Тёмный режим','Cancel'=>'Отмена','Delete Custom Style'=>'Удалить пользовательский стиль','Are you sure you want to delete this %1s? %2s %3s'=>'Вы уверены, что хотите удалить этот %1s? %2s %3s','Custom Style'=>'Пользовательский стиль','Save Custom Style'=>'Сохранить пользовательский стиль','Custom Admin Logo'=>'Пользовательский логотип администратора','Upload a custom logo to replace the WordPress icon in the admin bar. Recommended: 20px by 20px in SVG or PNG format.'=>'Загрузите пользовательский логотип, чтобы заменить иконку WordPress на админ панели. Рекомендуется: 20px на 20px в формате SVG или PNG.','Select Image'=>'Выберите изображение','Custom Favicon'=>'Пользовательский фавикон','Upload a custom favicon for the admin area. Recommended: 16px by 16px or 32px by 32px in SVG or PNG format.'=>'Загрузите пользовательский фавикон для админ-области. Рекомендуется: 16px на 16px или 32px на 32px в формате SVG или PNG.','Admin Footer Text'=>'Текст нижнего колонтитула администратора','Replace the default "Thanks for creating with WordPress" message in the admin footer.'=>'Замените сообщение по умолчанию "Спасибо за создание с WordPress" в нижнем колонтитуле администратора.','Replace "Howdy"'=>'Заменить "Howdy"','Replace "Howdy" in the admin bar.'=>'Заменить "Howdy" в панели администратора.','Control Settings'=>'Настройки управления','Control how admin styles are applied to users.'=>'Контролируйте, как стили администратора применяются к пользователям.','Hide Admin Color Scheme settings in user profile'=>'Скрыть настройки цветовой схемы администратора в профиле пользователя','When enabled, users cannot see or change color scheme settings in their profile. Role-based settings will be applied.'=>'Когда включено, пользователи не могут видеть или изменять настройки цветовой схемы в своем профиле. Настройки на основе роли будут применены.','Force role settings (override user selection)'=>'Принудительные настройки роли (перезапись выбора пользователя)','When enabled, role settings will always apply, overriding any user selection even if the color scheme UI is visible to them.'=>'Когда включено, настройки роли всегда будут применяться, переопределяя любой выбор пользователя, даже если интерфейс цветовой схемы виден для них.','Admin Styles allows you to customize the WordPress admin area with your own branding.'=>'Админские стили позволяют настраивать область администратора WordPress с вашим собственным брендингом.','Features include:'=>'Возможности включают:','Custom admin color schemes'=>'Пользовательские цветовые схемы администратора','Replace the WordPress logo and favicon'=>'Заменить логотип WordPress и фавикон','Custom footer text'=>'Пользовательский текст подвала','Replace "Howdy" text'=>'Заменить текст "Howdy"','How to use Admin Styles'=>'Как использовать стили администратора','Security check failed.'=>'Проверка безопасности не удалась.','You do not have permission to manage admin styles.'=>'У вас нет разрешения для управления стилями админа.','No role specified.'=>'Роль не указана.','Use this Image'=>'Использовать это изображение','Saving...'=>'Сохранение...','Settings saved.'=>'Настройки сохранены.','Current logo preview'=>'Предварительный просмотр текущего логотипа','Add New Custom Style'=>'Добавить новый пользовательский стиль','Edit Custom Style'=>'Редактировать пользовательский стиль','Are you sure you want to delete "%s" custom style?'=>'Вы уверены, что хотите удалить пользовательский стиль "%s"?','this custom style'=>'этот пользовательский стиль','Primary Button'=>'Основная кнопка','Hover State'=>'Состояние при наведении','Notification'=>'Уведомление','Live preview of your custom color scheme'=>'Предварительный просмотр вашей пользовательской цветовой схемы','Custom Style Name is required.'=>'Имя пользовательского стиля обязательно.','Main Admin Color is required.'=>'Основной цвет администратора обязателен.','PublishPress Custom'